patch:
diff --git a/llvm/lib/Analysis/InstructionSimplify.cpp b/llvm/lib/Analysis/InstructionSimplify.cpp
index a8823117cdb51..135a09ac1c792 100644
--- a/llvm/lib/Analysis/InstructionSimplify.cpp
+++ b/llvm/lib/Analysis/InstructionSimplify.cpp
@@ -4108,13 +4108,16 @@ static Value *simplifyFCmpInst(CmpPredicate Pred, Value *LHS, Value *RHS,
   assert(CmpInst::isFPPredicate(Pred) && "Not an FP compare!");

   if (Constant *CLHS = dyn_cast<Constant>(LHS)) {
-    if (Constant *CRHS = dyn_cast<Constant>(RHS))
-      return ConstantFoldCompareInstOperands(Pred, CLHS, CRHS, Q.DL, Q.TLI,
-                                             Q.CxtI);
-
-    // If we have a constant, make sure it is on the RHS.
-    std::swap(LHS, RHS);
-    Pred = CmpInst::getSwappedPredicate(Pred);
+    if (Constant *CRHS = dyn_cast<Constant>(RHS)) {
+      // if the folding isn't successfull, fall back to the rest of the logic
+      if (auto *Result = ConstantFoldCompareInstOperands(Pred, CLHS, CRHS, Q.DL,
+                                                         Q.TLI, Q.CxtI))
+        return Result;
+    } else {
+      // If we have a constant, make sure it is on the RHS.
+      std::swap(LHS, RHS);
+      Pred = CmpInst::getSwappedPredicate(Pred);
+    }
   }

   // Fold trivial predicates.

tests.test_body:
define i1 @bitcast_first() {
  %lhs = bitcast half 0xH7C00 to bfloat
  %cmp = fcmp ogt bfloat %lhs, 0xR7F80
  ret i1 %cmp
}

@g = external global i8

define i1 @bitcast_cannot_be_folded() {
  %cmp = fcmp ogt bfloat bitcast (i16 ptrtoint (ptr @g to i16) to bfloat), 0xR7F80
  ret i1 %cmp
}

define i1 @direct_bitcast() {
  %cmp = fcmp ogt bfloat bitcast (half 0xH7C00 to bfloat), 0xR7F80
  ret i1 %cmp
}

define i1 @direct_bitcast_uge() {
  %cmp = fcmp uge bfloat bitcast (half 0xH7C00 to bfloat), 0xRFF80
  ret i1 %cmp
}
